import{_ as s,o as t,c as n,ag as e}from"./chunks/framework.DgcAjFZS.js";const p="/learning-notes/images/openclaw-architecture.svg",k=JSON.parse('{"title":"深度解析：一张图拆解OpenClaw的Agent核心设计","description":"","frontmatter":{},"headers":[],"relativePath":"agent/openclaw-design.md","filePath":"agent/openclaw-design.md"}'),i={name:"agent/openclaw-design.md"};function l(d,a,o,r,h,c){return t(),n("div",null,[...a[0]||(a[0]=[e('<h1 id="深度解析-一张图拆解openclaw的agent核心设计" tabindex="-1">深度解析：一张图拆解OpenClaw的Agent核心设计 <a class="header-anchor" href="#深度解析-一张图拆解openclaw的agent核心设计" aria-label="Permalink to &quot;深度解析：一张图拆解OpenClaw的Agent核心设计&quot;">​</a></h1><blockquote><p>OpenClaw 是一个开源的 AI Agent 框架，它把一个无状态的 LLM 变成了一个持续在线、有记忆、有主动性的长期工作伙伴。本文从架构层面拆解它的核心设计，看看它是怎么做到的。</p></blockquote><h2 id="_1-引言-为什么-openclaw-值得拆解" tabindex="-1">1. 引言：为什么 OpenClaw 值得拆解 <a class="header-anchor" href="#_1-引言-为什么-openclaw-值得拆解" aria-label="Permalink to &quot;1. 引言：为什么 OpenClaw 值得拆解&quot;">​</a></h2><p>市面上的 Agent 框架不少，但大多数停留在&quot;工具调用链&quot;的层面——给 LLM 接几个 API，跑一个 ReAct 循环，就叫 Agent 了。</p><p>OpenClaw 走了一条不同的路。它不追求复杂的编排引擎或花哨的 DAG 工作流，而是用一组朴素的抽象——<strong>文件、定时器、消息路由</strong>——把一个 LLM 变成了一个真正意义上的&quot;数字伙伴&quot;：</p><ul><li><strong>有记忆</strong>：不是靠超长 context window 硬塞，而是用 Markdown 文件做持久化，配合向量+关键词混合检索按需召回</li><li><strong>有主动性</strong>：不只是&quot;问一句答一句&quot;，而是通过心跳轮询和定时任务主动巡逻、主动通知</li><li><strong>有人格</strong>：通过 SOUL.md、IDENTITY.md 等文件定义性格和行为边界，每次会话启动时&quot;恢复自我&quot;</li><li><strong>多触点</strong>：一个 Agent 同时接入 WhatsApp、Telegram、Discord、Signal 等多个消息通道，记忆跨通道共享</li><li><strong>可透视</strong>：所有状态都是纯文本文件，用户随时可以打开查看、编辑，甚至用 Git 做版本管理</li></ul><p>这篇文章会从架构全景开始，逐层拆解 OpenClaw 的核心设计，帮你理解它为什么能做到这些。</p><hr><h2 id="_2-架构全景图" tabindex="-1">2. 架构全景图 <a class="header-anchor" href="#_2-架构全景图" aria-label="Permalink to &quot;2. 架构全景图&quot;">​</a></h2><p><img src="'+p+`" alt="OpenClaw 架构全景图"></p><p>整个系统的核心是一个单进程的 <strong>Gateway 守护进程</strong>，它同时扮演了消息网关、Agent 运行时、会话管理器和工具调度器的角色。所有外部通道（WhatsApp、Telegram、Discord 等）通过各自的 SDK 接入 Gateway，消息经过路由分发到对应的 Agent，Agent 在一个序列化的循环中完成推理和工具调用，最终将结果流式返回给用户。</p><p>下面我们逐层拆解每个组件。</p><hr><h2 id="_3-gateway-中枢神经系统" tabindex="-1">3. Gateway：中枢神经系统 <a class="header-anchor" href="#_3-gateway-中枢神经系统" aria-label="Permalink to &quot;3. Gateway：中枢神经系统&quot;">​</a></h2><p>Gateway 是 OpenClaw 的心脏。它是一个长驻的 Node.js 进程，承担了三个核心职责：消息接入、协议通信、多 Agent 路由。</p><h3 id="_3-1-多通道统一接入" tabindex="-1">3.1 多通道统一接入 <a class="header-anchor" href="#_3-1-多通道统一接入" aria-label="Permalink to &quot;3.1 多通道统一接入&quot;">​</a></h3><p>Gateway 内置了多个消息通道的 SDK：</p><table tabindex="0"><thead><tr><th>通道</th><th>实现方式</th><th>说明</th></tr></thead><tbody><tr><td>WhatsApp</td><td>Baileys (Web API)</td><td>扫码登录，一个 Gateway 一个 WhatsApp 会话</td></tr><tr><td>Telegram</td><td>grammY</td><td>通过 BotFather 创建 Bot</td></tr><tr><td>Discord</td><td>discord.js</td><td>需要 Bot Token + Message Content Intent</td></tr><tr><td>Signal</td><td>signal-cli</td><td>通过 Signal CLI 桥接</td></tr><tr><td>Slack</td><td>Slack SDK</td><td>支持 Workspace 级别接入</td></tr><tr><td>iMessage</td><td>BlueBubbles</td><td>仅 macOS</td></tr><tr><td>WebChat</td><td>内置 HTTP</td><td>Gateway 自带的 Web 聊天界面</td></tr></tbody></table><p>所有通道的消息最终都被标准化为统一的内部格式，进入同一个处理管线。这意味着用户在 WhatsApp 上说的话，Agent 在 Telegram 上也&quot;记得&quot;——因为它们共享同一个 Session。</p><p><strong>设计亮点：Provider 抽象层</strong></p><p>每个通道实现一个统一的 Provider 接口，负责：</p><ul><li>消息接收：将平台特定格式转为内部 envelope</li><li>消息发送：将 Agent 回复转为平台特定格式</li><li>状态管理：连接状态、认证状态、在线状态</li></ul><p>这层抽象让新增通道变得简单——实现 Provider 接口即可，不需要改动 Agent 运行时的任何代码。</p><h3 id="_3-2-websocket-协议" tabindex="-1">3.2 WebSocket 协议 <a class="header-anchor" href="#_3-2-websocket-协议" aria-label="Permalink to &quot;3.2 WebSocket 协议&quot;">​</a></h3><p>Gateway 对外暴露一个 WebSocket API（默认 <code>127.0.0.1:18789</code>），所有控制面客户端（CLI、macOS App、WebChat、自动化脚本）都通过这个 WS 连接与 Gateway 通信。</p><p>协议设计简洁：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>客户端 → Gateway:  { type: &quot;req&quot;, id, method, params }</span></span>
<span class="line"><span>Gateway → 客户端:  { type: &quot;res&quot;, id, ok, payload }</span></span>
<span class="line"><span>Gateway → 客户端:  { type: &quot;event&quot;, event, payload }  // 推送</span></span></code></pre></div><p><strong>连接生命周期：</strong></p><ol><li>客户端发送 <code>connect</code> 帧（必须是第一帧），携带设备身份和认证 token</li><li>Gateway 验证身份，返回 <code>hello-ok</code>（包含 presence 和 health 快照）</li><li>之后进入正常的请求-响应 + 事件推送模式</li><li>支持幂等键去重，防止网络抖动导致的重复请求</li></ol><p><strong>安全机制：</strong></p><ul><li>设备配对：新设备首次连接需要审批，Gateway 颁发 device token</li><li>本地连接（loopback）可以自动审批，保持本机使用的流畅体验</li><li>远程连接必须显式审批 + token 认证</li><li>所有连接都需要签名 challenge nonce</li></ul><h3 id="_3-3-多-agent-路由与-bindings" tabindex="-1">3.3 多 Agent 路由与 Bindings <a class="header-anchor" href="#_3-3-多-agent-路由与-bindings" aria-label="Permalink to &quot;3.3 多 Agent 路由与 Bindings&quot;">​</a></h3><p>OpenClaw 支持在一个 Gateway 中运行多个完全隔离的 Agent，每个 Agent 有自己的：</p><ul><li><strong>Workspace</strong>（文件、人格、记忆）</li><li><strong>Session Store</strong>（会话历史）</li><li><strong>Auth Profile</strong>（API 密钥）</li><li><strong>agentDir</strong>（状态目录）</li></ul><p>通过 <code>bindings</code> 配置，消息可以按通道、账号、发送者、群组等维度路由到不同的 Agent：</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">bindings: [</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // WhatsApp 个人号 → home agent</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">agentId</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;home&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">match</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">channel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;whatsapp&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">accountId</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;personal&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> } },</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // WhatsApp 工作号 → work agent</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">agentId</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;work&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">match</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">channel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;whatsapp&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">accountId</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;biz&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> } },</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // 特定群组 → 专用 agent</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">agentId</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;family&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">match</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    channel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;whatsapp&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    peer</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">kind</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;group&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">id</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;xxx@g.us&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }},</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><p><strong>路由优先级（从高到低）：</strong></p><ol><li><code>peer</code> 精确匹配（特定的人或群）</li><li><code>parentPeer</code> 匹配（线程继承）</li><li><code>guildId + roles</code>（Discord 角色路由）</li><li><code>guildId</code>（Discord 服务器）</li><li><code>teamId</code>（Slack 团队）</li><li><code>accountId</code> 匹配</li><li><code>channel</code> 级别匹配</li><li>默认 Agent（fallback）</li></ol><p>这套路由机制非常灵活。你可以做到：一个 WhatsApp 号码，不同的人发消息过来，路由到不同的 Agent（不同的人格、不同的记忆）。也可以让日常闲聊走便宜的 Sonnet 模型，深度工作走 Opus 模型。</p><hr><h2 id="_4-agent-loop-一次对话的完整生命周期" tabindex="-1">4. Agent Loop：一次对话的完整生命周期 <a class="header-anchor" href="#_4-agent-loop-一次对话的完整生命周期" aria-label="Permalink to &quot;4. Agent Loop：一次对话的完整生命周期&quot;">​</a></h2><p>当一条消息到达 Agent 时，会触发一个完整的 Agent Loop。这是 OpenClaw 最核心的执行路径。</p><h3 id="_4-1-完整流程" tabindex="-1">4.1 完整流程 <a class="header-anchor" href="#_4-1-完整流程" aria-label="Permalink to &quot;4.1 完整流程&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户消息</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  消息入队        │ ← 根据队列模式决定处理方式</span></span>
<span class="line"><span>│  (Session Lane)  │</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  Session 加载    │ ← 从 JSONL 加载会话历史</span></span>
<span class="line"><span>│  + 写锁获取      │</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  上下文组装      │ ← System Prompt + Workspace 文件</span></span>
<span class="line"><span>│  (Context Build) │    + 会话历史 + 工具 Schema</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  模型推理        │ ← 调用 LLM API（流式）</span></span>
<span class="line"><span>│  (Inference)     │</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>    ┌────┴────┐</span></span>
<span class="line"><span>    │ 有工具   │ 无工具调用</span></span>
<span class="line"><span>    │ 调用？   │────────────┐</span></span>
<span class="line"><span>    └────┬────┘            │</span></span>
<span class="line"><span>         │ 是              │</span></span>
<span class="line"><span>         ▼                 │</span></span>
<span class="line"><span>┌─────────────────┐        │</span></span>
<span class="line"><span>│  工具执行        │        │</span></span>
<span class="line"><span>│  (Tool Execute)  │        │</span></span>
<span class="line"><span>└────────┬────────┘        │</span></span>
<span class="line"><span>         │                 │</span></span>
<span class="line"><span>         │ 结果反馈给模型   │</span></span>
<span class="line"><span>         └──────┐          │</span></span>
<span class="line"><span>                │          │</span></span>
<span class="line"><span>         ┌──────▼──────┐   │</span></span>
<span class="line"><span>         │  继续推理    │   │</span></span>
<span class="line"><span>         │  (下一轮)    │   │</span></span>
<span class="line"><span>         └──────┬──────┘   │</span></span>
<span class="line"><span>                │          │</span></span>
<span class="line"><span>                ▼          ▼</span></span>
<span class="line"><span>         ┌─────────────────┐</span></span>
<span class="line"><span>         │  流式输出        │ ← assistant/tool/lifecycle 三条流</span></span>
<span class="line"><span>         │  + 持久化        │ ← 写入 JSONL 会话文件</span></span>
<span class="line"><span>         └─────────────────┘</span></span></code></pre></div><h3 id="_4-2-队列与并发控制" tabindex="-1">4.2 队列与并发控制 <a class="header-anchor" href="#_4-2-队列与并发控制" aria-label="Permalink to &quot;4.2 队列与并发控制&quot;">​</a></h3><p>每个 Session 有一个独立的执行队列（session lane），保证同一个会话内的消息严格串行处理。这避免了并发导致的状态竞争。</p><p>当 Agent 正在处理一条消息时，新消息的处理取决于队列模式：</p><table tabindex="0"><thead><tr><th>模式</th><th>行为</th><th>适用场景</th></tr></thead><tbody><tr><td><strong>steer</strong></td><td>新消息注入当前运行，Agent 可以&quot;转向&quot;</td><td>需要实时纠正 Agent 行为</td></tr><tr><td><strong>followup</strong></td><td>排队等待，当前轮结束后自动开始下一轮</td><td>默认模式，保证顺序</td></tr><tr><td><strong>collect</strong></td><td>收集多条消息，合并后一起处理</td><td>用户连续发多条消息</td></tr></tbody></table><p><strong>steer 模式的实现细节：</strong> 队列在每次工具调用后检查是否有新消息。如果有，当前 assistant 消息中剩余的工具调用会被跳过（返回 &quot;Skipped due to queued user message&quot;），然后新消息被注入，模型重新开始推理。</p><h3 id="_4-3-上下文组装-context-build" tabindex="-1">4.3 上下文组装（Context Build） <a class="header-anchor" href="#_4-3-上下文组装-context-build" aria-label="Permalink to &quot;4.3 上下文组装（Context Build）&quot;">​</a></h3><p>每次运行前，OpenClaw 会组装完整的上下文，这是模型&quot;看到&quot;的全部信息：</p><p><strong>System Prompt 构成：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────┐</span></span>
<span class="line"><span>│           System Prompt              │</span></span>
<span class="line"><span>├─────────────────────────────────────┤</span></span>
<span class="line"><span>│ 1. 基础指令（OpenClaw 内置）         │</span></span>
<span class="line"><span>│    - 工具使用规范                    │</span></span>
<span class="line"><span>│    - 回复格式要求                    │</span></span>
<span class="line"><span>│    - 安全边界                        │</span></span>
<span class="line"><span>├─────────────────────────────────────┤</span></span>
<span class="line"><span>│ 2. 工具列表 + 描述                   │</span></span>
<span class="line"><span>│    - 每个工具的名称和简介             │</span></span>
<span class="line"><span>├─────────────────────────────────────┤</span></span>
<span class="line"><span>│ 3. Skills 列表（仅元数据）           │</span></span>
<span class="line"><span>│    - 名称 + 描述 + 文件位置          │</span></span>
<span class="line"><span>│    - 不包含完整说明，按需读取         │</span></span>
<span class="line"><span>├─────────────────────────────────────┤</span></span>
<span class="line"><span>│ 4. 运行时元数据                      │</span></span>
<span class="line"><span>│    - 时间（UTC + 用户时区）          │</span></span>
<span class="line"><span>│    - 主机信息、模型信息              │</span></span>
<span class="line"><span>│    - 当前 thinking/verbose 状态      │</span></span>
<span class="line"><span>├─────────────────────────────────────┤</span></span>
<span class="line"><span>│ 5. Project Context（Workspace 文件） │</span></span>
<span class="line"><span>│    - AGENTS.md（操作指南）           │</span></span>
<span class="line"><span>│    - SOUL.md（人格定义）             │</span></span>
<span class="line"><span>│    - USER.md（用户信息）             │</span></span>
<span class="line"><span>│    - IDENTITY.md（Agent 身份）       │</span></span>
<span class="line"><span>│    - TOOLS.md（工具备注）            │</span></span>
<span class="line"><span>│    - HEARTBEAT.md（心跳清单）        │</span></span>
<span class="line"><span>└─────────────────────────────────────┘</span></span></code></pre></div><p><strong>上下文预算管理：</strong></p><ul><li>单文件最大注入 20,000 字符（<code>bootstrapMaxChars</code>）</li><li>所有文件总计最大 150,000 字符（<code>bootstrapTotalMaxChars</code>）</li><li>超出的文件会被截断并标记</li><li>工具 Schema（JSON）也占上下文，但不以文本形式展示</li></ul><p>用户可以通过 <code>/context list</code> 和 <code>/context detail</code> 命令查看上下文的详细构成和各部分占用。</p><h3 id="_4-4-流式输出与事件系统" tabindex="-1">4.4 流式输出与事件系统 <a class="header-anchor" href="#_4-4-流式输出与事件系统" aria-label="Permalink to &quot;4.4 流式输出与事件系统&quot;">​</a></h3><p>Agent Loop 的输出是完全流式的，通过三条事件流实时推送：</p><table tabindex="0"><thead><tr><th>事件流</th><th>内容</th><th>用途</th></tr></thead><tbody><tr><td><strong>assistant</strong></td><td>模型的文本输出 delta</td><td>实时显示打字效果</td></tr><tr><td><strong>tool</strong></td><td>工具的 start/update/end</td><td>展示工具执行进度</td></tr><tr><td><strong>lifecycle</strong></td><td>运行的 start/end/error</td><td>控制 UI 状态</td></tr></tbody></table><p><strong>Block Streaming（分块发送）：</strong> 对于长回复，OpenClaw 可以在文本块完成时就发送（而不是等整个回复结束），默认按 800-1200 字符分块，优先在段落边界切分。这在消息通道（如 WhatsApp）上体验更好。</p><h3 id="_4-5-hook-系统" tabindex="-1">4.5 Hook 系统 <a class="header-anchor" href="#_4-5-hook-系统" aria-label="Permalink to &quot;4.5 Hook 系统&quot;">​</a></h3><p>OpenClaw 在 Agent Loop 的关键节点提供了 Hook 拦截点：</p><table tabindex="0"><thead><tr><th>Hook</th><th>时机</th><th>用途</th></tr></thead><tbody><tr><td><code>before_model_resolve</code></td><td>模型选择前</td><td>动态切换模型/provider</td></tr><tr><td><code>before_prompt_build</code></td><td>上下文组装前</td><td>注入额外上下文</td></tr><tr><td><code>before_tool_call</code></td><td>工具执行前</td><td>拦截/修改工具参数</td></tr><tr><td><code>after_tool_call</code></td><td>工具执行后</td><td>修改工具结果</td></tr><tr><td><code>tool_result_persist</code></td><td>结果持久化前</td><td>转换存储格式</td></tr><tr><td><code>agent_end</code></td><td>运行结束</td><td>审计/统计</td></tr><tr><td><code>before_compaction</code></td><td>压缩前</td><td>观察/标注</td></tr><tr><td><code>message_received</code></td><td>消息到达</td><td>过滤/转换</td></tr><tr><td><code>message_sending</code></td><td>消息发出前</td><td>最后修改机会</td></tr></tbody></table><p>这套 Hook 系统让高级用户可以在不修改核心代码的情况下，深度定制 Agent 的行为。</p><hr><h2 id="_5-记忆系统-文件即记忆" tabindex="-1">5. 记忆系统：文件即记忆 <a class="header-anchor" href="#_5-记忆系统-文件即记忆" aria-label="Permalink to &quot;5. 记忆系统：文件即记忆&quot;">​</a></h2><p>这是 OpenClaw 最有特色的设计之一。它没有用向量数据库或专门的记忆服务，而是用<strong>纯 Markdown 文件</strong>作为记忆的存储介质。</p><h3 id="_5-1-双层记忆架构" tabindex="-1">5.1 双层记忆架构 <a class="header-anchor" href="#_5-1-双层记忆架构" aria-label="Permalink to &quot;5.1 双层记忆架构&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>记忆层级</span></span>
<span class="line"><span>├── MEMORY.md          ← 长期记忆（手动策展，类似&quot;大脑&quot;）</span></span>
<span class="line"><span>└── memory/</span></span>
<span class="line"><span>    ├── 2026-03-01.md  ← 每日笔记（当天发生了什么）</span></span>
<span class="line"><span>    ├── 2026-03-02.md</span></span>
<span class="line"><span>    └── 2026-03-03.md</span></span></code></pre></div><ul><li><strong>MEMORY.md</strong>：策展过的长期记忆，存放用户偏好、重要决定、持久事实。只在主会话（私聊）中加载，避免在群聊中泄露隐私。</li><li><strong>memory/YYYY-MM-DD.md</strong>：每日流水账，记录当天的交互和事件。每次会话启动时读取今天和昨天的文件。</li></ul><p>这个设计的精妙之处在于：</p><ol><li><strong>透明</strong>：用户可以直接打开文件查看 Agent 记了什么，甚至手动编辑</li><li><strong>可版本控制</strong>：整个记忆目录可以用 Git 管理，有完整的变更历史</li><li><strong>隐私可控</strong>：MEMORY.md 只在私聊加载，群聊中不会泄露</li><li><strong>成本可控</strong>：不需要额外的数据库或向量服务</li></ol><h3 id="_5-2-语义搜索-向量-bm25-混合检索" tabindex="-1">5.2 语义搜索：向量 + BM25 混合检索 <a class="header-anchor" href="#_5-2-语义搜索-向量-bm25-混合检索" aria-label="Permalink to &quot;5.2 语义搜索：向量 + BM25 混合检索&quot;">​</a></h3><p>光有文件还不够——如果记忆很多，不可能每次都全部塞进上下文。OpenClaw 提供了两个记忆工具：</p><ul><li><strong>memory_search</strong>：语义搜索，从所有记忆文件中检索相关片段</li><li><strong>memory_get</strong>：精确读取，按文件路径和行号获取特定内容</li></ul><p>搜索引擎采用<strong>混合检索</strong>策略：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>查询 → ┬→ 向量检索（语义匹配，措辞不同也能找到）</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>       └→ BM25 检索（关键词匹配，精确 token 如 ID、代码符号）</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>       ▼</span></span>
<span class="line"><span>    加权合并 → 时间衰减（可选）→ MMR 去重（可选）→ Top-K 结果</span></span></code></pre></div><ul><li><strong>向量检索</strong>擅长语义匹配：&quot;Mac Studio 网关主机&quot; vs &quot;运行网关的那台机器&quot;</li><li><strong>BM25 检索</strong>擅长精确匹配：错误码、变量名、IP 地址等</li><li><strong>时间衰减</strong>：最近的记忆权重更高（默认半衰期 30 天），避免半年前的笔记压过昨天的更新</li><li><strong>MMR 去重</strong>：减少重复片段，确保返回的结果覆盖不同方面</li></ul><h3 id="_5-3-自动记忆刷写-pre-compaction-flush" tabindex="-1">5.3 自动记忆刷写（Pre-Compaction Flush） <a class="header-anchor" href="#_5-3-自动记忆刷写-pre-compaction-flush" aria-label="Permalink to &quot;5.3 自动记忆刷写（Pre-Compaction Flush）&quot;">​</a></h3><p>当会话接近上下文窗口上限、即将触发压缩（compaction）时，OpenClaw 会自动插入一个<strong>静默的记忆刷写轮次</strong>，提醒模型把重要信息写入磁盘文件，避免压缩后丢失关键上下文。</p><p>这个机制是自动的，用户完全无感知。</p><hr><h2 id="_6-workspace-agent-的-人格磁盘" tabindex="-1">6. Workspace：Agent 的&quot;人格磁盘&quot; <a class="header-anchor" href="#_6-workspace-agent-的-人格磁盘" aria-label="Permalink to &quot;6. Workspace：Agent 的&quot;人格磁盘&quot;&quot;">​</a></h2><p>Workspace 是 Agent 的家目录，也是它的&quot;人格磁盘&quot;。每次会话启动时，OpenClaw 会把 Workspace 中的关键文件注入到上下文中，让 Agent &quot;恢复自我&quot;。</p><h3 id="_6-1-文件职责分工" tabindex="-1">6.1 文件职责分工 <a class="header-anchor" href="#_6-1-文件职责分工" aria-label="Permalink to &quot;6.1 文件职责分工&quot;">​</a></h3><table tabindex="0"><thead><tr><th>文件</th><th>职责</th><th>加载时机</th></tr></thead><tbody><tr><td><code>SOUL.md</code></td><td>人格、语气、行为边界</td><td>每次会话</td></tr><tr><td><code>AGENTS.md</code></td><td>操作指南、工作流程、记忆规则</td><td>每次会话</td></tr><tr><td><code>USER.md</code></td><td>用户信息（名字、时区、偏好）</td><td>每次会话</td></tr><tr><td><code>IDENTITY.md</code></td><td>Agent 的名字、物种、风格、Emoji</td><td>每次会话</td></tr><tr><td><code>TOOLS.md</code></td><td>本地工具备注（摄像头名、SSH 地址等）</td><td>每次会话</td></tr><tr><td><code>HEARTBEAT.md</code></td><td>心跳检查清单</td><td>每次心跳</td></tr><tr><td><code>BOOTSTRAP.md</code></td><td>首次启动仪式（完成后删除）</td><td>仅首次</td></tr><tr><td><code>MEMORY.md</code></td><td>长期记忆</td><td>仅主会话</td></tr></tbody></table><h3 id="_6-2-bootstrap-仪式-从零到-我是谁" tabindex="-1">6.2 Bootstrap 仪式：从零到&quot;我是谁&quot; <a class="header-anchor" href="#_6-2-bootstrap-仪式-从零到-我是谁" aria-label="Permalink to &quot;6.2 Bootstrap 仪式：从零到&quot;我是谁&quot;&quot;">​</a></h3><p>当 Workspace 是全新的（第一次使用），OpenClaw 会创建一个 <code>BOOTSTRAP.md</code> 文件，引导 Agent 和用户完成一次&quot;认识彼此&quot;的对话：</p><ol><li>Agent 问用户：你是谁？叫我什么？</li><li>一起决定 Agent 的名字、性格、风格</li><li>把结果写入 IDENTITY.md、USER.md、SOUL.md</li><li>删除 BOOTSTRAP.md——仪式完成，Agent &quot;出生&quot;了</li></ol><p>这个设计很有仪式感，让用户从第一次交互就感受到这不是一个冷冰冰的聊天机器人。</p><hr><h2 id="_7-主动性引擎-heartbeat-cron" tabindex="-1">7. 主动性引擎：Heartbeat + Cron <a class="header-anchor" href="#_7-主动性引擎-heartbeat-cron" aria-label="Permalink to &quot;7. 主动性引擎：Heartbeat + Cron&quot;">​</a></h2><p>这是 OpenClaw 区别于大多数 Agent 框架的关键特性——它不只是被动响应，还能主动行动。</p><h3 id="_7-1-heartbeat-心跳轮询" tabindex="-1">7.1 Heartbeat 心跳轮询 <a class="header-anchor" href="#_7-1-heartbeat-心跳轮询" aria-label="Permalink to &quot;7.1 Heartbeat 心跳轮询&quot;">​</a></h3><p>Heartbeat 是一个定时触发的 Agent 轮次（默认每 30 分钟），Gateway 会向 Agent 发送一个心跳消息：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Gateway 定时器</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼ 每 30 分钟</span></span>
<span class="line"><span>发送心跳 Prompt → Agent 主会话</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>Agent 检查：</span></span>
<span class="line"><span>├── HEARTBEAT.md 中的待办事项</span></span>
<span class="line"><span>├── 邮件是否有紧急消息？</span></span>
<span class="line"><span>├── 日历是否有即将到来的事件？</span></span>
<span class="line"><span>├── 是否需要主动联系用户？</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── 有事 → 发送通知给用户</span></span>
<span class="line"><span>    └── 没事 → 回复 HEARTBEAT_OK（静默丢弃）</span></span></code></pre></div><p>关键设计点：</p><ul><li><strong>HEARTBEAT_OK 静默处理</strong>：没事时 Agent 回复 HEARTBEAT_OK，Gateway 直接丢弃，用户无感知</li><li><strong>活跃时间窗口</strong>：可以配置只在白天运行（如 08:00-22:00），避免半夜打扰</li><li><strong>成本意识</strong>：心跳运行完整的 Agent 轮次，间隔越短 token 消耗越大</li></ul><h3 id="_7-2-heartbeat-vs-cron-的分工" tabindex="-1">7.2 Heartbeat vs Cron 的分工 <a class="header-anchor" href="#_7-2-heartbeat-vs-cron-的分工" aria-label="Permalink to &quot;7.2 Heartbeat vs Cron 的分工&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>Heartbeat</th><th>Cron</th></tr></thead><tbody><tr><td>时间精度</td><td>大约每 30 分钟</td><td>精确到分钟</td></tr><tr><td>会话隔离</td><td>在主会话中运行</td><td>独立 Session</td></tr><tr><td>适合场景</td><td>批量检查（邮件+日历+通知）</td><td>精确调度（每周一 9:00 报告）</td></tr><tr><td>上下文</td><td>有主会话的对话历史</td><td>无历史，干净的上下文</td></tr></tbody></table><hr><h2 id="_8-session-管理-状态的持久化与隔离" tabindex="-1">8. Session 管理：状态的持久化与隔离 <a class="header-anchor" href="#_8-session-管理-状态的持久化与隔离" aria-label="Permalink to &quot;8. Session 管理：状态的持久化与隔离&quot;">​</a></h2><h3 id="_8-1-session-key-映射" tabindex="-1">8.1 Session Key 映射 <a class="header-anchor" href="#_8-1-session-key-映射" aria-label="Permalink to &quot;8.1 Session Key 映射&quot;">​</a></h3><p>OpenClaw 用 Session Key 来标识和隔离不同的对话上下文：</p><table tabindex="0"><thead><tr><th>场景</th><th>Session Key</th><th>说明</th></tr></thead><tbody><tr><td>私聊（默认）</td><td><code>agent:main:main</code></td><td>所有私聊共享</td></tr><tr><td>私聊（隔离）</td><td><code>agent:main:telegram:dm:123</code></td><td>按通道+发送者隔离</td></tr><tr><td>群聊</td><td><code>agent:main:whatsapp:group:xxx</code></td><td>每个群独立</td></tr><tr><td>Cron 任务</td><td><code>cron:job-id</code></td><td>每次运行独立</td></tr></tbody></table><p>默认所有私聊共享一个主 Session（<code>dmScope: &quot;main&quot;</code>），跨通道保持上下文连续。多用户场景可切换到 <code>per-channel-peer</code> 模式隔离。</p><h3 id="_8-2-compaction-上下文压缩" tabindex="-1">8.2 Compaction 上下文压缩 <a class="header-anchor" href="#_8-2-compaction-上下文压缩" aria-label="Permalink to &quot;8.2 Compaction 上下文压缩&quot;">​</a></h3><p>当会话历史太长、接近上下文窗口上限时，OpenClaw 自动触发 Compaction：</p><ol><li>触发记忆刷写（把重要信息写入文件）</li><li>将旧的对话历史压缩为一段摘要</li><li>保留最近的消息不变</li><li>摘要 + 最近消息 = 新的上下文</li></ol><p>这样 Agent 既不会&quot;失忆&quot;，又不会撑爆上下文窗口。</p><hr><h2 id="_9-工具与技能系统" tabindex="-1">9. 工具与技能系统 <a class="header-anchor" href="#_9-工具与技能系统" aria-label="Permalink to &quot;9. 工具与技能系统&quot;">​</a></h2><p>OpenClaw 的工具系统分为三层：内置工具、Skills 模块、扩展能力（Sub-agents + Nodes）。</p><h3 id="_9-1-内置工具" tabindex="-1">9.1 内置工具 <a class="header-anchor" href="#_9-1-内置工具" aria-label="Permalink to &quot;9.1 内置工具&quot;">​</a></h3><p>这些是 Agent 始终可用的基础能力：</p><table tabindex="0"><thead><tr><th>工具</th><th>功能</th><th>说明</th></tr></thead><tbody><tr><td><code>read</code></td><td>读取文件</td><td>支持文本和图片</td></tr><tr><td><code>write</code></td><td>写入文件</td><td>自动创建父目录</td></tr><tr><td><code>edit</code></td><td>精确编辑</td><td>基于文本匹配的 surgical edit</td></tr><tr><td><code>exec</code></td><td>执行命令</td><td>支持 PTY、后台运行、超时控制</td></tr><tr><td><code>process</code></td><td>管理进程</td><td>轮询、写入、发送按键、终止</td></tr><tr><td><code>browser</code></td><td>浏览器控制</td><td>截图、快照、自动化操作</td></tr><tr><td><code>message</code></td><td>发送消息</td><td>跨通道消息、投票、反应</td></tr><tr><td><code>memory_search</code></td><td>记忆搜索</td><td>语义检索记忆文件</td></tr><tr><td><code>memory_get</code></td><td>记忆读取</td><td>精确读取记忆片段</td></tr><tr><td><code>web_search</code></td><td>网页搜索</td><td>Brave Search API</td></tr><tr><td><code>web_fetch</code></td><td>网页抓取</td><td>URL → Markdown</td></tr><tr><td><code>tts</code></td><td>文字转语音</td><td>支持多种声音</td></tr><tr><td><code>sessions_spawn</code></td><td>创建子 Agent</td><td>独立 Session 并行执行</td></tr><tr><td><code>nodes</code></td><td>设备控制</td><td>拍照、截屏、定位、执行命令</td></tr></tbody></table><p>工具的可用性由 <strong>Tool Policy</strong> 控制，而不是 TOOLS.md（TOOLS.md 只是用户给 Agent 的使用备注）。</p><h3 id="_9-2-skills-模块化加载" tabindex="-1">9.2 Skills 模块化加载 <a class="header-anchor" href="#_9-2-skills-模块化加载" aria-label="Permalink to &quot;9.2 Skills 模块化加载&quot;">​</a></h3><p>Skills 是 OpenClaw 的能力扩展机制。每个 Skill 是一个独立的目录：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>skills/</span></span>
<span class="line"><span>├── weather/</span></span>
<span class="line"><span>│   ├── SKILL.md        ← 使用说明（模型按需读取）</span></span>
<span class="line"><span>│   └── ...             ← 可选的脚本、配置</span></span>
<span class="line"><span>├── clawhub/</span></span>
<span class="line"><span>│   ├── SKILL.md</span></span>
<span class="line"><span>│   └── ...</span></span>
<span class="line"><span>└── healthcheck/</span></span>
<span class="line"><span>    ├── SKILL.md</span></span>
<span class="line"><span>    └── ...</span></span></code></pre></div><p><strong>加载优先级（高到低）：</strong></p><ol><li>Workspace 内的 <code>skills/</code> 目录（项目级）</li><li>用户级 <code>~/.openclaw/skills/</code>（全局）</li><li>内置 Skills（随安装包分发）</li></ol><p><strong>关键设计：延迟加载</strong></p><p>System Prompt 中只注入 Skills 的<strong>名称和描述</strong>（元数据列表），不注入完整的使用说明。模型在判断需要某个 Skill 时，才去 <code>read</code> 对应的 SKILL.md。</p><p>这个设计的好处：</p><ul><li><strong>节省上下文</strong>：10 个 Skill 的元数据可能只占 2000 字符，但完整说明可能占 20000+</li><li><strong>按需加载</strong>：大多数对话只需要 0-1 个 Skill</li><li><strong>易于扩展</strong>：新增 Skill 只需要放一个目录，不需要改任何配置</li></ul><p><strong>Skill 市场（ClawHub）：</strong> OpenClaw 提供了一个类似 npm 的 Skill 市场（clawhub.com），可以搜索、安装、发布 Skills：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawhub</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> search</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> weather</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawhub</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> weather</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawhub</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --all</span></span></code></pre></div><h3 id="_9-3-sub-agents-子-agent-并行" tabindex="-1">9.3 Sub-agents 子 Agent 并行 <a class="header-anchor" href="#_9-3-sub-agents-子-agent-并行" aria-label="Permalink to &quot;9.3 Sub-agents 子 Agent 并行&quot;">​</a></h3><p>对于复杂任务，Agent 可以 spawn 子 Agent 在独立的 Session 中并行工作：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>主 Agent</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── spawn(&quot;分析这段代码的性能瓶颈&quot;, mode=&quot;run&quot;)</span></span>
<span class="line"><span>    │       → 子 Agent A（独立 Session，一次性任务）</span></span>
<span class="line"><span>    │       → 完成后自动汇报结果</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── spawn(&quot;监控这个服务的日志&quot;, mode=&quot;session&quot;)</span></span>
<span class="line"><span>    │       → 子 Agent B（独立 Session，持久任务）</span></span>
<span class="line"><span>    │       → 可以通过 steer 发送后续指令</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    └── 主 Agent 继续处理其他事情</span></span></code></pre></div><p><strong>两种模式：</strong></p><table tabindex="0"><thead><tr><th>模式</th><th>行为</th><th>适用场景</th></tr></thead><tbody><tr><td><code>run</code></td><td>一次性执行，完成后自动结束</td><td>独立的分析/生成任务</td></tr><tr><td><code>session</code></td><td>持久运行，可以持续交互</td><td>需要多轮对话的复杂任务</td></tr></tbody></table><p>子 Agent 可以指定不同的模型（比如用便宜的模型做简单任务），完成后通过 push 机制自动通知主 Agent，不需要轮询。</p><h3 id="_9-4-nodes-设备配对与远程控制" tabindex="-1">9.4 Nodes 设备配对与远程控制 <a class="header-anchor" href="#_9-4-nodes-设备配对与远程控制" aria-label="Permalink to &quot;9.4 Nodes 设备配对与远程控制&quot;">​</a></h3><p>OpenClaw 可以配对物理设备（手机、电脑、IoT），通过 WebSocket 连接实现远程控制：</p><p><strong>支持的设备能力：</strong></p><table tabindex="0"><thead><tr><th>能力</th><th>说明</th></tr></thead><tbody><tr><td><code>camera.snap</code></td><td>拍照（前置/后置/双摄）</td></tr><tr><td><code>camera.clip</code></td><td>录制短视频</td></tr><tr><td><code>screen.record</code></td><td>屏幕录制</td></tr><tr><td><code>location.get</code></td><td>获取地理位置</td></tr><tr><td><code>canvas.*</code></td><td>在设备上展示 UI</td></tr><tr><td>自定义命令</td><td>通过 <code>invoke</code> 执行设备端命令</td></tr></tbody></table><p><strong>配对流程：</strong></p><ol><li>设备（手机/电脑）安装 OpenClaw Node 客户端</li><li>连接到 Gateway 的 WebSocket，声明 <code>role: node</code></li><li>Gateway 发起配对审批</li><li>审批通过后，设备成为可用 Node</li><li>Agent 可以通过 <code>nodes</code> 工具调用设备能力</li></ol><p>这让 Agent 的能力从纯软件扩展到了物理世界——比如&quot;帮我拍一张前门的照片&quot;、&quot;我现在在哪里&quot;。</p><h3 id="_9-5-plugin-系统" tabindex="-1">9.5 Plugin 系统 <a class="header-anchor" href="#_9-5-plugin-系统" aria-label="Permalink to &quot;9.5 Plugin 系统&quot;">​</a></h3><p>除了 Skills，OpenClaw 还有一个更底层的 Plugin 系统，用于扩展 Gateway 本身的能力：</p><ul><li><strong>消息通道插件</strong>：新增消息平台支持</li><li><strong>记忆插件</strong>：替换默认的记忆搜索引擎（如 QMD）</li><li><strong>Hook 插件</strong>：在 Agent Loop 的各个节点注入自定义逻辑</li><li><strong>工具插件</strong>：注册新的工具供 Agent 使用</li></ul><p>Plugin 和 Skill 的区别：</p><ul><li><strong>Skill</strong> = Agent 层面的能力扩展（模型可以读取和使用）</li><li><strong>Plugin</strong> = Gateway 层面的系统扩展（影响整个运行时行为）</li></ul><hr><h2 id="_10-设计哲学总结" tabindex="-1">10. 设计哲学总结 <a class="header-anchor" href="#_10-设计哲学总结" aria-label="Permalink to &quot;10. 设计哲学总结&quot;">​</a></h2><p>拆解完 OpenClaw 的核心设计，可以提炼出几个鲜明的设计哲学：</p><h3 id="文件-数据库" tabindex="-1">文件 &gt; 数据库 <a class="header-anchor" href="#文件-数据库" aria-label="Permalink to &quot;文件 &gt; 数据库&quot;">​</a></h3><p>记忆用 Markdown，会话用 JSONL，配置用 JSON5。没有 PostgreSQL，没有 Redis，没有 MongoDB。文件系统就是数据库，<code>cat</code> 就是查询语言，Git 就是备份方案。</p><p>这不是技术倒退，而是刻意的选择——<strong>透明性</strong>比性能更重要。当你的 AI 伙伴记住了什么、忘记了什么，你应该能直接看到，而不是去翻数据库。</p><h3 id="心跳-事件驱动" tabindex="-1">心跳 &gt; 事件驱动 <a class="header-anchor" href="#心跳-事件驱动" aria-label="Permalink to &quot;心跳 &gt; 事件驱动&quot;">​</a></h3><p>没有复杂的事件总线或消息队列，一个简单的定时器就够了。每 30 分钟问一句&quot;有什么需要关注的吗？&quot;——简单、可靠、够用。</p><h3 id="透明-黑盒" tabindex="-1">透明 &gt; 黑盒 <a class="header-anchor" href="#透明-黑盒" aria-label="Permalink to &quot;透明 &gt; 黑盒&quot;">​</a></h3><p>SOUL.md 定义人格，MEMORY.md 存储记忆，AGENTS.md 规定行为——所有影响 Agent 行为的因素都是可见的、可编辑的纯文本文件。没有隐藏的 embedding、没有不可解释的向量空间，你改一行 SOUL.md，Agent 的性格就变了。</p><h3 id="简单组合-复杂框架" tabindex="-1">简单组合 &gt; 复杂框架 <a class="header-anchor" href="#简单组合-复杂框架" aria-label="Permalink to &quot;简单组合 &gt; 复杂框架&quot;">​</a></h3><p>OpenClaw 没有发明新的编排语言，没有 DAG 引擎，没有状态机。它用的都是最基础的组件：</p><ul><li>文件系统 → 记忆和人格</li><li>定时器 → 主动性</li><li>WebSocket → 通信</li><li>Markdown → 一切配置和内容</li></ul><p>这些组件的组合，产生了远超各部分之和的效果。这也许是 OpenClaw 最值得学习的地方——<strong>好的架构不是堆砌复杂度，而是找到正确的简单抽象</strong>。</p><hr><blockquote><p>📌 项目地址：<a href="https://github.com/openclaw/openclaw" target="_blank" rel="noreferrer">github.com/openclaw/openclaw</a></p><p>📖 官方文档：<a href="https://docs.openclaw.ai" target="_blank" rel="noreferrer">docs.openclaw.ai</a></p><p>💬 社区：<a href="https://discord.com/invite/clawd" target="_blank" rel="noreferrer">Discord</a></p><p>🔧 技能市场：<a href="https://clawhub.com" target="_blank" rel="noreferrer">clawhub.com</a></p></blockquote>`,162)])])}const u=s(i,[["render",l]]);export{k as __pageData,u as default};
